import{_ as a,c as l,o as s,a1 as t}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"호환성: Claude Code 스킬 | opencode-agent-skills","description":"OpenCode Agent Skills가 Claude Code 스킬과 플러그인 시스템을 어떻게 호환하는지 학습합니다. 도구 매핑 메커니즘, 스킬 발견 우선순위를 익히고 Claude 스킬 생태계를 재사용하세요.","frontmatter":{"title":"호환성: Claude Code 스킬 | opencode-agent-skills","sidebarTitle":"Claude 스킬 재사용","subtitle":"Claude Code 스킬 호환성","description":"OpenCode Agent Skills가 Claude Code 스킬과 플러그인 시스템을 어떻게 호환하는지 학습합니다. 도구 매핑 메커니즘, 스킬 발견 우선순위를 익히고 Claude 스킬 생태계를 재사용하세요.","tags":["호환성","Claude Code","스킬 재사용"],"prerequisite":["start-what-is-opencode-agent-skills","platforms-skill-discovery-mechanism"],"order":1},"headers":[],"relativePath":"ko/joshuadavidthomas/opencode-agent-skills/advanced/claude-code-compatibility/index.md","filePath":"ko/joshuadavidthomas/opencode-agent-skills/advanced/claude-code-compatibility/index.md"}'),d={name:"ko/joshuadavidthomas/opencode-agent-skills/advanced/claude-code-compatibility/index.md"};function o(i,e,n,r,c,p){return s(),l("div",null,[...e[0]||(e[0]=[t(`<h1 id="claude-code-스킬-호환성" tabindex="-1">Claude Code 스킬 호환성 <a class="header-anchor" href="#claude-code-스킬-호환성" aria-label="Permalink to &quot;Claude Code 스킬 호환성&quot;">​</a></h1><h2 id="이-수업을-마치면-할-수-있는-것" tabindex="-1">이 수업을 마치면 할 수 있는 것 <a class="header-anchor" href="#이-수업을-마치면-할-수-있는-것" aria-label="Permalink to &quot;이 수업을 마치면 할 수 있는 것&quot;">​</a></h2><ul><li>플러그인이 Claude Code 스킬 형식을 자동으로 호환하는 방식 이해</li><li>도구 매핑 메커니즘을 마스터하여 Claude 스킬이 OpenCode에서 올바르게 작동하도록 함</li><li>스킬 발견의 전체 우선순위 규칙 이해</li><li>Claude 플러그인 마켓플레이스의 기존 스킬을 다시 작성하지 않고 재사용</li></ul><h2 id="현재의-어려움" tabindex="-1">현재의 어려움 <a class="header-anchor" href="#현재의-어려움" aria-label="Permalink to &quot;현재의 어려움&quot;">​</a></h2><p>Claude Code 스킬이 이미 있거나 Claude 플러그인 마켓플레이스의 스킬을 사용하려고 하지만, 이러한 스킬은 Claude Code용으로 작성되었습니다. OpenCode에서 직접 사용하면 문제가 발생합니다:</p><ul><li>Claude 스킬의 도구 호출(예: <code>TodoWrite</code>, <code>Task</code>)이 OpenCode에 존재하지 않음</li><li>OpenCode가 설치된 Claude 플러그인 스킬을 어떻게 찾는지 불분명</li><li>스킬 형식이 호환되지 않을까 걱정하여 모든 내용을 다시 작성해야 함</li></ul><h2 id="핵심-아이디어" tabindex="-1">핵심 아이디어 <a class="header-anchor" href="#핵심-아이디어" aria-label="Permalink to &quot;핵심 아이디어&quot;">​</a></h2><p>OpenCode Agent Skills 플러그인은 <strong>3단계 호환 메커니즘</strong>을 통해 수정 없이 Claude Code 스킬을 사용할 수 있게 해줍니다:</p><ol><li><strong>자동 발견</strong> - Claude Code의 표준 디렉터리(<code>.claude/skills/</code>, <code>~/.claude/plugins/</code>)에서 스킬 스캔</li><li><strong>도구 매핑</strong> - 스킬 로드 시 자동으로 도구 매핑 가이드를 주입하여 Claude 도구명을 OpenCode 도구명으로 변환</li><li><strong>형식 지원</strong> - Claude 플러그인의 v1 및 v2 두 가지 설치 형식 모두 지원</li></ol><div class="info custom-block"><p class="custom-block-title">핵심 개념</p><p><strong>Claude Code 스킬 형식</strong> - Anthropic이 정의한 스킬 사양으로, <code>SKILL.md</code> 파일을 사용하여 스킬을 설명하며, YAML frontmatter(메타데이터)와 Markdown 콘텐츠(지침)를 포함합니다.</p></div><h3 id="도구-매핑-원리" tabindex="-1">도구 매핑 원리 <a class="header-anchor" href="#도구-매핑-원리" aria-label="Permalink to &quot;도구 매핑 원리&quot;">​</a></h3><p>플러그인이 Claude Code로 작성된 스킬을 감지하면 자동으로 도구 매핑 가이드를 주입합니다:</p><table tabindex="0"><thead><tr><th>Claude Code 도구</th><th>OpenCode 도구</th><th>매핑 규칙</th></tr></thead><tbody><tr><td><code>TodoWrite/TodoRead</code></td><td><code>todowrite/todoread</code></td><td>소문자</td></tr><tr><td><code>Task</code> (하위 에이전트)</td><td><code>task</code> (subagent_type 파라미터 사용)</td><td>파라미터 변경</td></tr><tr><td><code>Skill</code></td><td><code>use_skill</code></td><td>도구명 교체</td></tr><tr><td><code>Read/Write/Edit/Bash/Glob/Grep/WebFetch</code></td><td><code>read/write/edit/bash/glob/grep/webfetch</code></td><td>소문자</td></tr></tbody></table><p><strong>매핑 방식</strong>: 플러그인은 스킬을 로드할 때 매핑 가이드를 XML 형식으로 세션 컨텍스트에 주입하고, AI는 이에 따라 올바른 도구를 호출합니다.</p><div class="tip custom-block"><p class="custom-block-title">매핑이 필요한 이유는?</p><p>Claude Code와 OpenCode의 도구 명명 규칙이 다릅니다. Claude는 PascalCase(예: <code>TodoWrite</code>)를 사용하고, OpenCode는 소문자(예: <code>todowrite</code>)를 사용합니다. 도구 매핑을 통해 AI가 호출을 변환하는 방법을 알 수 있게 해줍니다.</p></div><h3 id="스킬-발견-우선순위" tabindex="-1">스킬 발견 우선순위 <a class="header-anchor" href="#스킬-발견-우선순위" aria-label="Permalink to &quot;스킬 발견 우선순위&quot;">​</a></h3><p>플러그인은 다음 순서로 스킬을 발견하며, <strong>첫 번째로 매칭된 스킬이 적용</strong>됩니다(동일 이름의 스킬은 중복되지 않음):</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[스킬 발견 흐름] --&gt; B[프로젝트 수준 OpenCode]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; |.opencode/skills/| C[1. project]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[프로젝트 수준 Claude Code]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; |.claude/skills/| E[2. claude-project]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[사용자 수준 OpenCode]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; |~/.config/opencode/skills/| G[3. user]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H[사용자 수준 Claude Code]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    H --&gt; |~/.claude/skills/| I[4. claude-user]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    I --&gt; J[Claude 플러그인 캐시]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    J --&gt; |~/.claude/plugins/cache/| K[5. claude-plugins]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    K --&gt; L[Claude 플러그인 마켓플레이스]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    L --&gt; |~/.claude/plugins/marketplaces/| M[6. claude-plugins]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#e1f5e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style E fill:#fff4e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style G fill:#e1f5e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style I fill:#fff4e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style K fill:#fff4e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style M fill:#fff4e1</span></span></code></pre></div><p><strong>우선순위 규칙</strong>:</p><ul><li>프로젝트 수준 스킬이 사용자 수준 스킬을 덮어씀(프로젝트 맞춤화 용이)</li><li>OpenCode 스킬이 Claude 스킬보다 우선(혼란 방지)</li><li>동일 이름의 스킬은 처음 발견된 버전만 유지</li></ul><details class="details custom-block"><summary>예시: 동일 이름 스킬 덮어쓰기</summary><p>두 위치에 모두 <code>git-helper</code>라는 이름의 스킬이 있다고 가정:</p><ul><li><code>.claude/skills/git-helper/SKILL.md</code> (Claude 버전)</li><li><code>.opencode/skills/git-helper/SKILL.md</code> (OpenCode 버전)</li></ul><p><strong>결과</strong>: OpenCode 버전이 적용됨(우선순위가 더 높음)</p></details><h2 id="🎒-시작-전-준비-사항" tabindex="-1">🎒 시작 전 준비 사항 <a class="header-anchor" href="#🎒-시작-전-준비-사항" aria-label="Permalink to &quot;🎒 시작 전 준비 사항&quot;">​</a></h2><ul><li>OpenCode Agent Skills 플러그인이 설치 및 설정됨</li><li>기본 스킬 개념 이해(권장: <a href="./../../start/what-is-opencode-agent-skills/">OpenCode Agent Skills란?</a> 먼저 읽기)</li><li>(선택사항) Claude Code에 설치된 플러그인이나 스킬 있음</li></ul><h2 id="따라-하기" tabindex="-1">따라 하기 <a class="header-anchor" href="#따라-하기" aria-label="Permalink to &quot;따라 하기&quot;">​</a></h2><h3 id="_1단계-claude-스킬이-발견되는지-확인" tabindex="-1">1단계: Claude 스킬이 발견되는지 확인 <a class="header-anchor" href="#_1단계-claude-스킬이-발견되는지-확인" aria-label="Permalink to &quot;1단계: Claude 스킬이 발견되는지 확인&quot;">​</a></h3><p><strong>이유</strong> 플러그인이 Claude Code 스킬 디렉터리를 올바르게 스캔할 수 있는지 확인합니다.</p><p>OpenCode에서 도구 호출:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>get_available_skills()</span></span></code></pre></div><p><strong>볼 수 있는 내용</strong>: 반환된 스킬 목록에 <code>.claude/skills/</code>, <code>~/.claude/skills/</code>, <code>~/.claude/plugins/</code>의 스킬이 포함되어 있으며, 각 스킬의 <code>source</code> 필드에 소스가 표시됨(예: <code>claude-project</code>, <code>claude-user</code>, <code>claude-plugins</code>).</p><p><strong>체크포인트 ✅</strong>: 목록에 예상된 Claude 스킬이 포함되어 있는지 확인.</p><h3 id="_2단계-claude-스킬-로드" tabindex="-1">2단계: Claude 스킬 로드 <a class="header-anchor" href="#_2단계-claude-스킬-로드" aria-label="Permalink to &quot;2단계: Claude 스킬 로드&quot;">​</a></h3><p><strong>이유</strong> 도구 매핑 메커니즘이 정상적으로 작동하는지 검증합니다.</p><p>Claude 스킬을 로드하려면 도구 호출:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>use_skill(skill=&quot;your-skill-name&quot;)</span></span></code></pre></div><p><strong>볼 수 있는 내용</strong>: <code>Skill &quot;xxx&quot; loaded.</code>와 같은 성공 메시지가 반환됨.</p><p><strong>체크포인트 ✅</strong>: 이제 AI가 해당 스킬의 지침을 사용할 수 있음.</p><h3 id="_3단계-도구-매핑이-적용되는지-확인" tabindex="-1">3단계: 도구 매핑이 적용되는지 확인 <a class="header-anchor" href="#_3단계-도구-매핑이-적용되는지-확인" aria-label="Permalink to &quot;3단계: 도구 매핑이 적용되는지 확인&quot;">​</a></h3><p><strong>이유</strong> AI가 OpenCode의 도구를 Claude의 도구 대신 올바르게 호출하는지 확인합니다.</p><p>AI에 해당 스킬 도구가 필요한 작업을 요청합니다. 예:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>스킬의 todo 기능을 사용하여 작업 목록을 만들어주세요.</span></span></code></pre></div><p><strong>볼 수 있는 내용</strong>: AI가 Claude의 <code>TodoWrite</code> 도구 대신 OpenCode의 <code>todowrite</code> 도구를 올바르게 호출함.</p><div class="tip custom-block"><p class="custom-block-title">매핑이 적용되는지 어떻게 확인하나요?</p><p>디버그 모드가 활성화된 경우 AI의 도구 호출 로그를 확인하면, <code>todowrite</code>를 호출하는 것을 볼 수 있고 <code>TodoWrite</code>는 호출하지 않습니다.</p></div><p><strong>체크포인트 ✅</strong>: 도구 호출이 성공하고 작업이 완료됨.</p><h2 id="문제-해결-팁" tabindex="-1">문제 해결 팁 <a class="header-anchor" href="#문제-해결-팁" aria-label="Permalink to &quot;문제 해결 팁&quot;">​</a></h2><h3 id="_1-플러그인-형식-불일치" tabindex="-1">1. 플러그인 형식 불일치 <a class="header-anchor" href="#_1-플러그인-형식-불일치" aria-label="Permalink to &quot;1. 플러그인 형식 불일치&quot;">​</a></h3><p><strong>문제</strong>: 이전 버전의 Claude 플러그인이 v1 형식을 사용하고 최신 버전이 v2 형식을 사용하여 일부 스킬을 발견할 수 없음.</p><p><strong>원인</strong>: v1과 v2의 <code>installed_plugins.json</code> 구조가 다름.</p><p><strong>해결</strong>: 플러그인은 두 형식을 모두 지원하며 수동 변환이 필요하지 않음. 그럼에도 스킬을 발견할 수 없는 경우, <code>~/.claude/plugins/installed_plugins.json</code>이 존재하고 형식이 올바른지 확인.</p><h3 id="_2-도구-매핑이-적용되지-않음" tabindex="-1">2. 도구 매핑이 적용되지 않음 <a class="header-anchor" href="#_2-도구-매핑이-적용되지-않음" aria-label="Permalink to &quot;2. 도구 매핑이 적용되지 않음&quot;">​</a></h3><p><strong>문제</strong>: AI가 여전히 Claude 도구명을 호출하여 오류가 발생함.</p><p><strong>원인</strong>: 스킬 콘텐츠가 도구 매핑 가이드를 우회하거나 하드코딩된 도구 호출을 사용했을 수 있음.</p><p><strong>해결</strong>:</p><ul><li>스킬이 로드된 후에 사용하는지, 도구를 직접 호출하는 것이 아닌지 확인</li><li>스킬에 코드 예시가 있는 경우, 도구명을 OpenCode 형식으로 수동으로 변경</li></ul><h3 id="_3-스킬-이름-충돌" tabindex="-1">3. 스킬 이름 충돌 <a class="header-anchor" href="#_3-스킬-이름-충돌" aria-label="Permalink to &quot;3. 스킬 이름 충돌&quot;">​</a></h3><p><strong>문제</strong>: 같은 이름의 스킬이 서로 다른 위치에 있을 때 잘못된 버전이 로드됨.</p><p><strong>원인</strong>: 스킬 발견 우선순위로 인한 덮어쓰기.</p><p><strong>해결</strong>:</p><ul><li>스킬의 <code>source</code> 필드를 확인하여 출처 확인</li><li>네임스페이스 형식을 사용하여 출처를 명확히 지정: <code>use_skill(skill=&quot;user:skill-name&quot;)</code> 또는 <code>use_skill(skill=&quot;claude-plugins:skill-name&quot;)</code></li></ul><details class="details custom-block"><summary>네임스페이스 구문</summary><p>플러그인은 <code>namespace:skill-name</code> 형식을 지원합니다:</p><ul><li><code>project:skill-name</code> - 프로젝트 수준 OpenCode 스킬</li><li><code>claude-project:skill-name</code> - 프로젝트 수준 Claude 스킬</li><li><code>user:skill-name</code> - 사용자 수준 OpenCode 스킬</li><li><code>claude-user:skill-name</code> - 사용자 수준 Claude 스킬</li><li><code>claude-plugins:skill-name</code> - Claude 플러그인 마켓플레이스 스킬</li></ul></details><h2 id="수업-요약" tabindex="-1">수업 요약 <a class="header-anchor" href="#수업-요약" aria-label="Permalink to &quot;수업 요약&quot;">​</a></h2><p>OpenCode Agent Skills 플러그인은 3단계 호환 메커니즘을 통해 Claude Code 스킬을 원활하게 재사용할 수 있게 해줍니다:</p><ul><li><strong>자동 발견</strong> - 6개 위치에서 스킬을 스캔하여 프로젝트 수준, 사용자 수준, 플러그인 수준을 모두 커버</li><li><strong>도구 매핑</strong> - Claude 도구명을 자동으로 OpenCode 도구명으로 변환</li><li><strong>형식 지원</strong> - v1과 v2 두 가지 Claude 플러그인 형식을 모두 지원</li></ul><p>스킬을 다시 작성할 필요 없이 바로 설치하여 사용하면 플러그인이 자동으로 호환성 문제를 처리합니다.</p><h2 id="다음-수업-예고" tabindex="-1">다음 수업 예고 <a class="header-anchor" href="#다음-수업-예고" aria-label="Permalink to &quot;다음 수업 예고&quot;">​</a></h2><blockquote><p>다음 수업에서는 **<a href="./../superpowers-integration/">Superpowers 워크플로 통합</a>**을 배웁니다.</p><p>배울 내용:</p><ul><li>Superpowers 모드를 활성화하는 방법</li><li>Superpowers 스킬의 자동 감지 및 로드</li><li>엄격한 워크플로가 개발 효율성을 높이는 방법</li></ul></blockquote><hr><h2 id="부록-소스-코드-참조" tabindex="-1">부록: 소스 코드 참조 <a class="header-anchor" href="#부록-소스-코드-참조" aria-label="Permalink to &quot;부록: 소스 코드 참조&quot;">​</a></h2><details><summary><strong>클릭하여 소스 코드 위치 보기</strong></summary><blockquote><p>업데이트 시간: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>기능</th><th>파일 경로</th><th>행 번호</th></tr></thead><tbody><tr><td>도구 매핑 정의</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L19-L25" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>19-25</td></tr><tr><td>v1/v2 형식 타입 정의</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L35-L61" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>35-61</td></tr><tr><td>플러그인 설치 경로 추출</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L68-L77" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>68-77</td></tr><tr><td>플러그인 스킬 발견</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L82-L105" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>82-105</td></tr><tr><td>마켓플레이스 스킬 발견</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L115-L180" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>115-180</td></tr><tr><td>캐시 스킬 발견</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L193-L253" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>193-253</td></tr><tr><td>스킬 발견 우선순위 목록</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L241-L254" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>241-254</td></tr><tr><td>동일 이름 스킬 중복 제거 로직</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L256-L260" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>256-260</td></tr><tr><td>toolTranslation 가져오기</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L15" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>15</td></tr><tr><td>도구 매핑 주입</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L238-L249" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>238-249</td></tr></tbody></table><p><strong>주요 상수</strong>:</p><ul><li><code>toolTranslation</code>: 스킬 로드 시 세션 컨텍스트에 주입되는 도구 매핑 가이드 XML 문자열. <code>src/claude.ts:19-25</code>에서 정의되고 <code>src/tools.ts:15</code>에서 가져옴</li></ul><p><strong>주요 함수</strong>:</p><ul><li><code>getPluginInstallPaths()</code>: v1/v2 형식에서 플러그인 설치 경로 추출</li><li><code>discoverSkillsFromPluginDir()</code>: 플러그인 디렉터리의 skills/ 하위 디렉터리 스캔</li><li><code>discoverMarketplaceSkills()</code>: <code>~/.claude/plugins/marketplaces/</code>에서 스킬 발견(우선)</li><li><code>discoverPluginCacheSkills()</code>: <code>~/.claude/plugins/cache/</code>에서 스킬 발견(폴백)</li><li><code>findFile()</code>: 지정된 파일명을 재귀적으로 검색(유틸리티 함수)</li></ul><p><strong>중요한 흐름</strong>:</p><ol><li>플러그인 초기화 시 <code>discoverAllSkills()</code> 호출 → 6개 발견 경로 순회</li><li>Claude 플러그인 스킬 발견 시 <code>discoverMarketplaceSkills()</code> 또는 <code>discoverPluginCacheSkills()</code> 호출</li><li>스킬 로드 시 <code>use_skill</code> 도구가 XML 콘텐츠에 <code>toolTranslation</code> 삽입(244행)</li></ol></details>`,68)])])}const g=a(d,[["render",o]]);export{h as __pageData,g as default};
